/// <reference types="cypress" />
import {
  apiLogin,
  apiCreateWorkspace,
  apiCreateChannel,
  apiCreatePost,
  apiLogout,
  uniqueName,
  DB_URL,
} from "./helpers";

describe("Live Update Tests", () => {
  const wsName = uniqueName("LiveWS");
  const chName = "LiveChannel";

  before(() => {
    // Preload workspace, channel, and posts via API
    apiLogin("live_setup_user").then((token) => {
      apiCreateWorkspace(token, wsName);
      apiCreateChannel(token, wsName, chName);
      apiCreatePost(token, wsName, chName, "Live post alpha");
      apiCreatePost(token, wsName, chName, "Live post beta");
      apiLogout(token);
    });
  });

  beforeEach(() => {
    cy.visit("/");
    cy.login("live_user");
    cy.openWorkspace(wsName);
    cy.openChannel(chName);
    cy.contains("Live post alpha").should("exist");
    cy.contains("Live post beta").should("exist");
  });

  afterEach(() => {
    cy.logout();
  });

  it("should display new posts at bottom of channel", () => {
    // Create a post as another user via the UI in a new tab isn't possible,
    // so we use the app's own createPost command (simulates typing)
    cy.createPost("New live post gamma");

    cy.contains("New live post gamma").should("exist");

    cy.contains("Live post beta").then(($beta) => {
      cy.contains("New live post gamma").then(($gamma) => {
        expect($gamma[0].getBoundingClientRect().top).to.be.greaterThan(
          $beta[0].getBoundingClientRect().top,
        );
      });
    });
  });

  it("should display new replies in correct location", () => {
    cy.getPost("Live post alpha").replyToPost("Live new reply to alpha");

    cy.contains("Live new reply to alpha").should("exist");

    cy.contains("Live new reply to alpha").then(($newReply) => {
      cy.contains("Live post beta").then(($beta) => {
        expect($newReply[0].getBoundingClientRect().top).to.be.lessThan(
          $beta[0].getBoundingClientRect().top,
        );
      });
    });
  });

  it("should display live channel in order", () => {
    cy.createPost("Live order post 1");
    cy.createPost("Live order post 2");
    cy.createPost("Live order post 3");

    cy.contains("Live order post 3").should("exist");

    cy.contains("Live order post 1").then(($p1) => {
      cy.contains("Live order post 2").then(($p2) => {
        cy.contains("Live order post 3").then(($p3) => {
          expect($p1[0].getBoundingClientRect().top).to.be.lessThan(
            $p2[0].getBoundingClientRect().top,
          );
