   854	function wrapComposer(kind: "italic" | "bold" | "link"): void {
   855	  const textarea = document.getElementById("post-input") as HTMLTextAreaElement | null;
   856	  if (!textarea) {
   857	    return;
   858	  }
   859	  const start = textarea.selectionStart;
   860	  const end = textarea.selectionEnd;
   861	  const selected = textarea.value.slice(start, end);
   862	  let replacement = selected;
   863	  if (kind === "italic") {
   864	    replacement = `*${selected}*`;
   865	  } else if (kind === "bold") {
   866	    replacement = `**${selected}**`;
   867	  } else {
   868	    replacement = `[${selected}](https://)`;
   869	  }
   870	  textarea.setRangeText(replacement, start, end, "end");
   871	  textarea.focus();
   872	}
